import{_ as t,o as i,c as a,a2 as s}from"./chunks/framework.jWxB9oXr.js";const u=JSON.parse(`{"title":"FAQ","description":"Frequently asked questions about Silvery — installation, Ink compatibility, performance, components, testing, and terminal support.","frontmatter":{"title":"FAQ","description":"Frequently asked questions about Silvery — installation, Ink compatibility, performance, components, testing, and terminal support.","faq":[{"q":"What is Silvery?","a":"Polished terminal apps in React. Silvery provides 45+ components, layout-first rendering with per-node dirty tracking, responsive layout via useBoxRect(), and full support for modern terminal protocols. Three principles guide the project: take the best from the web, stay true to the terminal, and raise the bar for developer ergonomics, architecture composability, and performance. It works with Bun and Node.js (23.6+)."},{"q":"How does Silvery compare to Ink?","a":"Both use React for terminal UIs. Silvery's key differences are layout-first rendering (components know their size during render via useBoxRect()), comparable performance with different strengths (Silvery faster on cursor/selection, Ink faster on content updates), bundle-parity with Ink+Yoga (114.9 KB vs 116.6 KB gzipped), a larger component library (45+ vs Ink's 6 core + @inkjs/ui's 13), and comprehensive terminal protocol support (Kitty keyboard, SGR mouse, graphics, synchronized output). Ink has a larger ecosystem and is the established standard."},{"q":"Is Silvery compatible with existing Ink code?","a":"Yes. Silvery provides a compatibility layer via silvery/ink and silvery/chalk that passes ~99% of Ink 7.0's test suite (918/931 tests). Most Ink code works with import path changes. See the migration guide for details."},{"q":"How fast is Silvery compared to Ink?","a":"Silvery is 3–27× faster depending on the scenario (up to 20× on memo'd interactive updates). Both are fast enough for 60fps at typical terminal sizes. The cell-level output phase also emits 10-20x less output than Ink's line-level diff on incremental updates. See the detailed benchmarks on the Silvery vs Ink page."},{"q":"What components does Silvery include?","a":"45+ components across layout (Box, SplitView, Divider), input (TextInput, TextArea, SelectList, CommandPalette, Form), display (Text, Badge, Spinner, ProgressBar, Table, Tabs, Toast), navigation (TreeView, ListView, VirtualList, Breadcrumb), and containers (Screen, ModalDialog, ScrollbackView). See the component catalog for the full list."},{"q":"Does Silvery work with Node.js and Bun?","a":"Yes. Silvery is pure TypeScript with no native dependencies or WASM. It works with Bun (any version) and Node.js 23.6+ (which has native TypeScript type stripping)."},{"q":"How do I test Silvery apps?","a":"Silvery provides two testing approaches. For fast unit tests, use createRenderer() from @silvery/test for headless rendering with text assertions. For full terminal verification (ANSI output, colors, scrollback, cursor positioning), use createTermless() which runs a real xterm.js emulator in-process."},{"q":"Does Silvery support mouse input?","a":"Yes. Silvery supports X10, button event tracking, and SGR extended mouse protocol (coordinates beyond 223). Components can handle onClick, onMouseDown, onMouseUp, and onMouseMove. Focus in/out reporting and mouse cursor shape (via OSC 22) are also supported."},{"q":"What terminal emulators does Silvery support?","a":"Silvery works with any terminal that supports basic ANSI escape sequences. Modern features like Kitty keyboard protocol, truecolor, synchronized output, and graphics are auto-detected at startup and enabled when available. Tested with Ghostty, Kitty, iTerm2, WezTerm, Alacritty, Windows Terminal, and others. See terminfo.dev for detailed compatibility data."},{"q":"How does theming work in Silvery?","a":"Silvery ships 38 color palettes with semantic tokens ($primary, $success, $muted, $danger, etc.). Themes auto-detect the terminal's background color and adjust for WCAG-compliant contrast. Use ThemeProvider to set a palette, then reference tokens in your components. See the styling guide and theme explorer for details."},{"q":"Is Silvery production-ready?","a":"Silvery is actively developed and used in production by a complex TUI application with thousands of nodes, multiple views, and rich interactions. The API surface is stabilizing but may have breaking changes before 1.0. It ships with comprehensive tests, including property-invariant fuzz tests for the rendering pipeline."},{"q":"Does Silvery have TypeScript support?","a":"Silvery is written entirely in TypeScript with strict mode enabled. All components, hooks, and APIs are fully typed. The package ships TypeScript source directly (no compiled JavaScript), which works with Bun natively and Node.js 23.6+ with type stripping."},{"q":"How does the layout engine work?","a":"Silvery uses Flexily, a Yoga-compatible flexbox layout engine written in pure TypeScript. Layout runs before rendering, so components can access their dimensions via useBoxRect(). This enables responsive layouts, native scrollable containers, and automatic text truncation without post-render measurement."},{"q":"Can I use Silvery for fullscreen terminal apps?","a":"Yes. Silvery supports both fullscreen mode (alternate screen buffer, absolute positioning, incremental diff) and inline mode (normal scrollback, relative positioning). Fullscreen is the default. Both modes use incremental rendering for efficient updates."},{"q":"How do I migrate from Ink to Silvery?","a":"Most Ink code works with minimal changes. Replace ink imports with silvery/ink, chalk with silvery/chalk, and you're running. For new code, use Silvery's native APIs (useBoxRect, SelectList, VirtualList) to take advantage of responsive layout and the full component library. See the migration guide for step-by-step instructions."}],"head":[["meta",{"property":"og:title","content":"FAQ"}],["meta",{"property":"og:description","content":"Frequently asked questions about Silvery — installation, Ink compatibility, performance, components, testing, and terminal support."}],["meta",{"property":"og:url","content":"https://silvery.dev/guide/faq.html"}],["link",{"rel":"canonical","href":"https://silvery.dev/guide/faq.html"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://silvery.dev/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Guide\\",\\"item\\":\\"https://silvery.dev/guide\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"FAQ\\",\\"item\\":\\"https://silvery.dev/guide/faq\\"}]}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"FAQ\\",\\"description\\":\\"Frequently asked questions about Silvery — installation, Ink compatibility, performance, components, testing, and terminal support.\\",\\"url\\":\\"https://silvery.dev/guide/faq.html\\",\\"dateModified\\":\\"2026-04-10T21:39:01.000Z\\",\\"datePublished\\":\\"2026-04-10T21:39:01.000Z\\",\\"image\\":\\"https://silvery.dev/og-image.png\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Bjørn Stabell\\",\\"url\\":\\"https://beorn.codes\\",\\"sameAs\\":[\\"https://github.com/beorn\\"]}}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"FAQPage\\",\\"mainEntity\\":[{\\"@type\\":\\"Question\\",\\"name\\":\\"What is Silvery?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Polished terminal apps in React. Silvery provides 45+ components, layout-first rendering with per-node dirty tracking, responsive layout via useBoxRect(), and full support for modern terminal protocols. Three principles guide the project: take the best from the web, stay true to the terminal, and raise the bar for developer ergonomics, architecture composability, and performance. It works with Bun and Node.js (23.6+).\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How does Silvery compare to Ink?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Both use React for terminal UIs. Silvery's key differences are layout-first rendering (components know their size during render via useBoxRect()), comparable performance with different strengths (Silvery faster on cursor/selection, Ink faster on content updates), bundle-parity with Ink+Yoga (114.9 KB vs 116.6 KB gzipped), a larger component library (45+ vs Ink's 6 core + @inkjs/ui's 13), and comprehensive terminal protocol support (Kitty keyboard, SGR mouse, graphics, synchronized output). Ink has a larger ecosystem and is the established standard.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Is Silvery compatible with existing Ink code?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes. Silvery provides a compatibility layer via silvery/ink and silvery/chalk that passes ~99% of Ink 7.0's test suite (918/931 tests). Most Ink code works with import path changes. See the migration guide for details.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How fast is Silvery compared to Ink?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery is 3–27× faster depending on the scenario (up to 20× on memo'd interactive updates). Both are fast enough for 60fps at typical terminal sizes. The cell-level output phase also emits 10-20x less output than Ink's line-level diff on incremental updates. See the detailed benchmarks on the Silvery vs Ink page.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What components does Silvery include?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"45+ components across layout (Box, SplitView, Divider), input (TextInput, TextArea, SelectList, CommandPalette, Form), display (Text, Badge, Spinner, ProgressBar, Table, Tabs, Toast), navigation (TreeView, ListView, VirtualList, Breadcrumb), and containers (Screen, ModalDialog, ScrollbackView). See the component catalog for the full list.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Does Silvery work with Node.js and Bun?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes. Silvery is pure TypeScript with no native dependencies or WASM. It works with Bun (any version) and Node.js 23.6+ (which has native TypeScript type stripping).\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I test Silvery apps?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery provides two testing approaches. For fast unit tests, use createRenderer() from @silvery/test for headless rendering with text assertions. For full terminal verification (ANSI output, colors, scrollback, cursor positioning), use createTermless() which runs a real xterm.js emulator in-process.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Does Silvery support mouse input?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes. Silvery supports X10, button event tracking, and SGR extended mouse protocol (coordinates beyond 223). Components can handle onClick, onMouseDown, onMouseUp, and onMouseMove. Focus in/out reporting and mouse cursor shape (via OSC 22) are also supported.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What terminal emulators does Silvery support?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery works with any terminal that supports basic ANSI escape sequences. Modern features like Kitty keyboard protocol, truecolor, synchronized output, and graphics are auto-detected at startup and enabled when available. Tested with Ghostty, Kitty, iTerm2, WezTerm, Alacritty, Windows Terminal, and others. See terminfo.dev for detailed compatibility data.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How does theming work in Silvery?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery ships 38 color palettes with semantic tokens ($primary, $success, $muted, $danger, etc.). Themes auto-detect the terminal's background color and adjust for WCAG-compliant contrast. Use ThemeProvider to set a palette, then reference tokens in your components. See the styling guide and theme explorer for details.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Is Silvery production-ready?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery is actively developed and used in production by a complex TUI application with thousands of nodes, multiple views, and rich interactions. The API surface is stabilizing but may have breaking changes before 1.0. It ships with comprehensive tests, including property-invariant fuzz tests for the rendering pipeline.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Does Silvery have TypeScript support?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery is written entirely in TypeScript with strict mode enabled. All components, hooks, and APIs are fully typed. The package ships TypeScript source directly (no compiled JavaScript), which works with Bun natively and Node.js 23.6+ with type stripping.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How does the layout engine work?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery uses Flexily, a Yoga-compatible flexbox layout engine written in pure TypeScript. Layout runs before rendering, so components can access their dimensions via useBoxRect(). This enables responsive layouts, native scrollable containers, and automatic text truncation without post-render measurement.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I use Silvery for fullscreen terminal apps?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes. Silvery supports both fullscreen mode (alternate screen buffer, absolute positioning, incremental diff) and inline mode (normal scrollback, relative positioning). Fullscreen is the default. Both modes use incremental rendering for efficient updates.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I migrate from Ink to Silvery?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Most Ink code works with minimal changes. Replace ink imports with silvery/ink, chalk with silvery/chalk, and you're running. For new code, use Silvery's native APIs (useBoxRect, SelectList, VirtualList) to take advantage of responsive layout and the full component library. See the migration guide for step-by-step instructions.\\"}}]}"]]},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1775857141000}`),o={name:"guide/faq.md"};function r(n,e,l,p,d,h){return i(),a("div",null,[...e[0]||(e[0]=[s("",67)])])}const m=t(o,[["render",r]]);export{u as __pageData,m as default};
